/**
 * API Route: Set Page as Default in Group
 * Author: generated by Amazon Q
 * Created: 2025-01-XX
 */

import { NextRequest, NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';
import { verifyToken } from '@/lib/auth';

const prisma = new PrismaClient();

export async function POST(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  try {
    const authHeader = request.headers.get('authorization');
    const token = authHeader?.replace('Bearer ', '');
    
    if (!token || !verifyToken(token)) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { id } = params;

    // دریافت صفحه
    const page = await prisma.page.findUnique({
      where: { id },
      select: { pageGroupId: true, language: true }
    });

    if (!page || !page.pageGroupId) {
      return NextResponse.json(
        { success: false, error: 'Page not found or not in a group' },
        { status: 404 }
      );
    }

    // تنظیم همه صفحات گروه به غیر پیشفرض
    await prisma.page.updateMany({
      where: { pageGroupId: page.pageGroupId },
      data: { isDefaultLang: false }
    });

    // تنظیم این صفحه به عنوان پیشفرض
    await prisma.page.update({
      where: { id },
      data: { isDefaultLang: true }
    });

    // بروزرسانی defaultLanguage در گروه
    await prisma.pageGroup.update({
      where: { id: page.pageGroupId },
      data: { defaultLanguage: page.language }
    });

    return NextResponse.json({
      success: true,
      message: 'Default page updated successfully'
    });

  } catch (error) {
    console.error('Error setting default page:', error);
    return NextResponse.json(
      {
        success: false,
        error: 'Failed to set default page',
        message: error instanceof Error ? error.message : 'Unknown error'
      },
      { status: 500 }
    );
  }
}
